  // src/traces/scatter/xy_defaults.ts
  function handleXYDefaults(traceIn, traceOut, layout, coerce3) {
    const x = coerce3("x");
    const y = coerce3("y");
    let len2;
    const handleCalendarDefaults = getComponentMethod("calendars", "handleTraceDefaults");
    handleCalendarDefaults(traceIn, traceOut, ["x", "y"], layout);
    if (x) {
      const xlen = minRowLength(x);
      if (y) {
        len2 = Math.min(xlen, minRowLength(y));
      } else {
        len2 = xlen;
        coerce3("y0");
        coerce3("dy");
      }
    } else {
      if (!y) return 0;
      len2 = minRowLength(y);
      coerce3("x0");
      coerce3("dx");
    }
    traceOut._length = len2;
    return len2;
  }

