  // src/components/modebar/buttons.ts
  var _ = lib_default._;
  var modeBarButtons = {};
  modeBarButtons.toImage = {
    name: "toImage",
    title: function(gd) {
      const opts = gd._context.toImageButtonOptions || {};
      const format6 = opts.format || "png";
      return format6 === "png" ? _(gd, "Download plot as a PNG") : (
        // legacy text
        _(gd, "Download plot")
      );
    },
    icon: ploticon_default.camera,
    click: function(gd) {
      const toImageButtonOptions = gd._context.toImageButtonOptions;
      const opts = { format: toImageButtonOptions.format || "png" };
      lib_default.notifier(_(gd, "Taking snapshot - this may take a few seconds"), "long");
      ["filename", "width", "height", "scale"].forEach((key) => {
        if (key in toImageButtonOptions) {
          opts[key] = toImageButtonOptions[key];
        }
      });
      download_default(gd, opts).then((filename) => {
        lib_default.notifier(_(gd, "Snapshot succeeded") + " - " + filename, "long");
      }).catch(() => {
        lib_default.notifier(_(gd, "Sorry, there was a problem downloading your snapshot!"), "long");
      });
    }
  };
  modeBarButtons.sendDataToCloud = {
    name: "sendDataToCloud",
    title: function(gd) {
      return _(gd, "Edit in Chart Studio");
    },
    icon: ploticon_default.disk,
    click: function(gd) {
      plots_default.sendDataToCloud(gd);
    }
  };
  modeBarButtons.editInChartStudio = {
    name: "editInChartStudio",
    title: function(gd) {
      return _(gd, "Edit in Chart Studio");
    },
    icon: ploticon_default.pencil,
    click: function(gd) {
      plots_default.sendDataToCloud(gd);
    }
  };
